class Solution:
    def restoreIpAddresses(self, s):
        n = len(s)
        res = []
        def ok(part):
            if not (1 <= len(part) <= 3):
                return False
            if len(part) > 1 and part[0] == '0':
                return False
            return int(part) <= 255
        for a in range(1, 4):
            for b in range(a + 1, a + 4):
                for c in range(b + 1, b + 4):
                    if c >= n:
                        continue
                    p1, p2, p3, p4 = s[:a], s[a:b], s[b:c], s[c:]
                    if ok(p1) and ok(p2) and ok(p3) and ok(p4):
                        res.append(p1 + '.' + p2 + '.' + p3 + '.' + p4)
        return res

