class Solution:
    def restoreIpAddresses(self, s):
        res = []
        n = len(s)
        def ok(part):
            if len(part) > 1 and part[0] == '0':
                return False
            return int(part) <= 255
        def back(start, parts):
            if len(parts) == 4:
                if start == n:
                    res.append('.'.join(parts))
                return
            for length in range(1, 4):
                if start + length > n:
                    break
                seg = s[start:start + length]
                if ok(seg):
                    back(start + length, parts + [seg])
        back(0, [])
        return res

