var restoreIpAddresses = function(s) {
    const res = [];
    const n = s.length;
    const ok = function(part) {
        if (part.length > 1 && part[0] === '0') return false;
        return parseInt(part, 10) <= 255;
    };
    const back = function(start, parts) {
        if (parts.length === 4) {
            if (start === n) res.push(parts.join('.'));
            return;
        }
        for (let len = 1; len <= 3; len++) {
            if (start + len > n) break;
            const seg = s.slice(start, start + len);
            if (ok(seg)) back(start + len, parts.concat([seg]));
        }
    };
    back(0, []);
    return res;
};
